+
+    if (fs.existsSync(sourcePath)) {
+      if (!fs.existsSync(targetPath) || options.force) {
+        copyDirRecursive(sourcePath, targetPath);
+        result.created.files.push(`.claude/skills/${skillName}`);
+        result.summary.skillsCount++;
+      } else {
