+  }
+
+  if (config.ruvSwarm) {
+    commands.push('claude mcp add ruv-swarm -- npx ruv-swarm mcp start');
+  }
+
+  if (config.flowNexus) {
+    commands.push('claude mcp add flow-nexus -- npx flow-nexus@latest mcp start');
